import dotenv from"dotenv";import path from"path";dotenv.config({path:path.resolve(__dirname,"../../../.env")});export const env={OPENROUTER_API_KEY:process.env.OPENROUTER_API_KEY||"",SUPABASE_URL:process.env.SUPABASE_URL||"",SUPABASE_ANON_KEY:process.env.SUPABASE_ANON_KEY||"",SUPABASE_SERVICE_ROLE_KEY:process.env.SUPABASE_SERVICE_ROLE_KEY||"",DATABASE_URL:process.env.DATABASE_URL||"",GROQ_API_KEY:process.env.GROQ_API_KEY||""};export function validateEnv(){const missing=[];for(const[key,value]of Object.entries(env))value||"OPENROUTER_API_KEY"===key||missing.push(key);if(missing.length>0)throw new Error(`Missing environment variables: ${missing.join(", ")}`);console.log("✅ Environment variables loaded")}